# Environment variables (set in Lambda configuration)
OUTPUT_BUCKET = os.environ.get("OUTPUT_BUCKET")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN")
ALLOWED_EXTENSIONS = frozenset(
    os.environ.get("ALLOWED_EXTENSIONS", ".jpg,.jpeg,.png,.gif,.bmp,.webp").split(",")
)
MAX_FILE_SIZE_BYTES = int(os.environ.get("MAX_FILE_SIZE_BYTES", str(50 * 1024 * 1024)))  # 50MB default

# Initialize clients outside handler for connection reuse
s3_client = boto3.client("s3")
sns_client = boto3.client("sns")


def validate_environment():
    """Validate required environment variables are set."""
    missing = []
    if not OUTPUT_BUCKET:
        missing.append("OUTPUT_BUCKET")
    if not SNS_TOPIC_ARN:
        missing.append("SNS_TOPIC_ARN")
    if missing:
        raise EnvironmentError(f"Missing required environment variables: {', '.join(missing)}")


def validate_s3_key(key):
    """Validate the S3 object key to prevent path traversal and ensure allowed file types."""
    if not key:
        raise ValueError("Empty S3 key")

    # Prevent path traversal
    normalized = os.path.normpath(key)
    if normalized.startswith("..") or "/../" in key or key.startswith("/"):
        raise ValueError(f"Invalid S3 key (potential path traversal): {key}")

    # Check file extension
    _, ext = os.path.splitext(key.lower())
    if ext not in ALLOWED_EXTENSIONS:
        raise ValueError(
            f"File extension '{ext}' not allowed. Permitted: {', '.join(sorted(ALLOWED_EXTENSIONS))}"
        )

    return key


def validate_content_type(content_type):
    """Validate the content type is an image MIME type."""
    allowed_content_types = {
        "image/jpeg",
        "image/png",
        "image/gif",
        "image/bmp",
        "image/webp",
    }
    if content_type and content_type.lower() not in allowed_content_types:
        raise ValueError(f"Content type '{content_type}' is not an allowed image type")


def read_image_from_s3(bucket, key):
    """Read an image object from S3 with validation."""
    logger.info("Reading object from s3://%s/%s", bucket, key)

    try:
        # First, check metadata without downloading the full object
        head_response = s3_client.head_object(Bucket=bucket, Key=key)
        content_length = head_response.get("ContentLength", 0)
        content_type = head_response.get("ContentType", "")

        if content_length > MAX_FILE_SIZE_BYTES:
            raise ValueError(
                f"File size {content_length} bytes exceeds maximum allowed "
                f"{MAX_FILE_SIZE_BYTES} bytes"
            )

        validate_content_type(content_type)

        # Download the object
        response = s3_client.get_object(Bucket=bucket, Key=key)
        image_data = response["Body"].read()

        logger.info(
            "Successfully read image: size=%d bytes, content_type=%s",
            len(image_data),
            content_type,
        )

        return {
            "data": image_data,
            "content_type": content_type,
            "content_length": content_length,
            "metadata": head_response.get("Metadata", {}),
        }

    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        if error_code == "NoSuchKey":
            logger.error("Object not found: s3://%s/%s", bucket, key)
            raise FileNotFoundError(f"Object not found: s3://{bucket}/{key}") from e
        elif error_code == "AccessDenied":
            logger.error("Access denied for s3://%s/%s", bucket, key)
            raise PermissionError(f"Access denied for s3://{bucket}/{key}") from e
        else:
            logger.error("S3 error reading s3://%s/%s: %s", bucket, key, str(e))
            raise


def process_image(image_info, source_key):
    """
    Process the image data. Replace this with actual image processing logic
    (e.g., resizing, thumbnail generation, metadata extraction, etc.)
    """
    logger.info("Processing image: %s (%d bytes)", source_key, len(image_info["data"]))

    # Placeholder processing result
    processing_result = {
        "source_key": source_key,
        "original_size_bytes": image_info["content_length"],
        "content_type": image_info["content_type"],
        "processed_at": datetime.utcnow().isoformat() + "Z",
        "processing_id": str(uuid.uuid4()),
        "status": "processed",
    }

    # In a real implementation, you would do actual image processing here:
    # - Generate thumbnails
    # - Extract EXIF data
    # - Run image recognition
    # - Resize/compress
    # For MVP, we pass through the image data and generate metadata
    processed_data = image_info["data"]

    logger.info("Image processing complete: processing_id=%s", processing_result["processing_id"])

    return processed_data, processing_result


def write_results_to_s3(processed_data, processing_result, source_key):
    """Write processed image and metadata to the output S3 bucket."""
    # Generate output key preserving directory structure but in output bucket
    base_name, ext = os.path.splitext(os.path.basename(source_key))
    processing_id = processing_result["processing_id"]
    timestamp = datetime.utcnow().strftime("%Y/%m/%d")

    # Output paths
    processed_image_key = f"processed/{timestamp}/{base_name}_{processing_id}{ext}"
    metadata_key = f"metadata/{timestamp}/{base_name}_{processing_id}.json"

    try:
        # Write processed image
        s3_client.put_object(
            Bucket=OUTPUT_BUCKET,
            Key=processed_image_key,
            Body=processed_data,
            ContentType=processing_result["content_type"],
            ServerSideEncryption="AES256",
            Metadata={
                "processing-id": processing_id,
                "source-key": source_key,
            },
        )
        logger.info("Wrote processed image to s3://%s/%s", OUTPUT_BUCKET, processed_image_key)

        # Write metadata JSON
        metadata_json = json.dumps(processing_result, indent=2, default=str)
        s3_client.put_object(
            Bucket=OUTPUT_BUCKET,
            Key=metadata_key,
            Body=metadata_json.encode("utf-8"),
            ContentType="application/json",
            ServerSideEncryption="AES256",
        )
        logger.info("Wrote metadata to s3://%s/%s", OUTPUT_BUCKET, metadata_key)

        return {
            "processed_image_key": processed_image_key,
            "metadata_key": metadata_key,
        }

    except ClientError as e:
        logger.error("Failed to write results to S3: %s", str(e))
        raise


def send_notification(processing_result, output_keys, source_bucket, source_key, success=True):
    """Send processing notification via SNS."""
    try:
        if success:
            subject = "Image Processing Complete"
            message = {
                "status": "success",
                "source": f"s3://{source_bucket}/{source_key}",
                "processing_id": processing_result["processing_id"],
                "processed_at": processing_result["processed_at"],
                "output_bucket": OUTPUT_BUCKET,
                "output_keys": output_keys,
            }
        else:
            subject = "Image Processing Failed"
            message = {
                "status": "failure",
                "source": f"s3://{source_bucket}/{source_key}",
                "error": str(processing_result),
            }

        sns_client.publish(
            TopicArn=SNS_TOPIC_ARN,
            Subject=subject[:100],  # SNS subject max 100 chars
            Message=json.dumps(message, indent=2, default=str),
            MessageAttributes={
                "status": {
                    "DataType": "String",
                    "StringValue": "success" if success else "failure",
                },
                "source_bucket": {
                    "DataType": "String",
                    "StringValue": source_bucket,
                },
            },
        )
        logger.info("Sent SNS notification: subject=%s", subject)

    except ClientError as e:
        # Log but don't fail the whole process if notification fails
        logger.error("Failed to send SNS notification: %s", str(e))


def lambda_handler(event, context):
    """
    Main Lambda handler. Triggered by S3 event notifications when
    images are uploaded to the input bucket.
    """
    logger.info("Received event: %s", json.dumps(event, default=str))

    validate_environment()

    results = []

    records = event.get("Records", [])
    if not records:
        logger.warning("No records found in event")
        return {
            "statusCode": 200,
            "body": json.dumps({"message": "No records to process"}),
        }

    for record in records:
        source_bucket = None
        source_key = None

        try:
            # Extract S3 event information
            s3_event = record.get("s3", {})
            source_bucket = s3_event.get("bucket", {}).get("name")
            raw_key = s3_event.get("object", {}).get("key")

            if not source_bucket or not raw_key:
                logger.error("Missing bucket or key in record: %s", json.dumps(record, default=str))
                continue

            # URL-decode the key (S3 event notifications URL-encode keys)
            source_key = unquote_plus(raw_key)

            # Validate the key
            source_key = validate_s3_key(source_key)

            # Ensure we're not reading from and writing to the same bucket/prefix
            # to prevent infinite loops
            if source_bucket == OUTPUT_BUCKET:
                logger.warning(
                    "Skipping object from output bucket to prevent infinite loop: %s",
                    source_key,
                )
                continue

            # Read image from S3
            image_info = read_image_from_s3(source_bucket, source_key)

            # Process the image
            processed_data, processing_result = process_image(image_info, source_key)

            # Write results to output bucket
            output_keys = write_results_to_s3(processed_data, processing_result, source_key)

            # Send success notification
            send_notification(
                processing_result, output_keys, source_bucket, source_key, success=True
            )

            results.append(
                {
                    "source": f"s3://{source_bucket}/{source_key}",
                    "status": "success",
                    "processing_id": processing_result["processing_id"],
                    "output_keys": output_keys,
                }
            )

            logger.info(
                "Successfully processed s3://%s/%s -> processing_id=%s",
                source_bucket,
                source_key,
                processing_result["processing_id"],
            )

        except (ValueError, FileNotFoundError) as e:
            logger.error(
                "Validation/not-found error processing s3://%s/%s: %s",
                source_bucket,
                source_key,
                str(e),
            )
            if source_bucket and source_key:
                send_notification(str(e), None, source_bucket, source_key, success=False)
            results.append(
                {
                    "source": f"s3://{source_bucket}/{source_key}",
                    "status": "error",
                    "error": str(e),
                }
            )

        except Exception as e:
            logger.exception(
                "Unexpected error processing s3://%s/%s: %s",
                source_bucket,
                source_key,
                str(e),
            )
            if source_bucket and source_key:
                send_notification(str(e), None, source_bucket, source_key, success=False)
            results.append(
                {
                    "source": f"s3://{source_bucket}/{source_key}",
                    "status": "error",
                    "error": str(e),
                }
            )

    response = {
        "statusCode": 200,
        "body": json.dumps(
            {
                "message": f"Processed {len(results)} image(s)",
                "results": results,
            },
            default=str,
        ),
    }

    logger.info("Lambda execution complete: %s", response["body"])
    return response